mapper.select:
select 
from pt_product p
where p.deleted = 0 and p.listing_status = 1
  and (p.unlisting_at is null or p.unlisting_at > now())

    AND p.product_type_id = #{productTypeId}


    AND p.service_type = #{serviceType}


    AND p.id IN (select product_id from pt_product_store_rel where store_id = #{storeId})

order by p.sort_no desc, p.id desc

    limit #{offset}, #{limit}

select count(*) from pt_product p
where p.deleted = 0 and p.listing_status = 1
  and (p.unlisting_at is null or p.unlisting_at > now())

    AND p.product_type_id = #{productTypeId}


    AND p.service_type = #{serviceType}


    AND p.id IN (select product_id from pt_product_store_rel where store_id = #{storeId})
